('business:4-1-production-processes:match:4d989d71', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Job Production”?", "options": ["The process of production where one type of product is made and then production is switched to make a different product.", "Production of one product that takes place continuously using a production or assembly line. Also called mass production.", "A production process involving machinery that is not controlled by a person but usually controlled by a computer.", "The process of production where products are made individually."]}'::jsonb, '{"answer": 3, "explain": "“Job Production” means: The process of production where products are made individually."}'::jsonb),
('business:4-1-production-processes:match:744417ce', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Batch Production”?", "options": ["Production of one product that takes place continuously using a production or assembly line. Also called mass production.", "A production process involving machinery that is not controlled by a person but usually controlled by a computer.", "The process of production where one type of product is made and then production is switched to make a different product.", "The use of robots in the process of production."]}'::jsonb, '{"answer": 2, "explain": "“Batch Production” means: The process of production where one type of product is made and then production is switched to make a different product."}'::jsonb),
('business:4-1-production-processes:match:14686a23', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Flow Production”?", "options": ["Production of one product that takes place continuously using a production or assembly line. Also called mass production.", "A production process involving machinery that is not controlled by a person but usually controlled by a computer.", "The use of robots in the process of production.", "A product made to the exact individual specification of a customer — unique to that person."]}'::jsonb, '{"answer": 0, "explain": "“Flow Production” means: Production of one product that takes place continuously using a production or assembly line. Also called mass production."}'::jsonb),
('business:4-1-production-processes:match:7621268d', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Automation”?", "options": ["The use of robots in the process of production.", "A product made to the exact individual specification of a customer — unique to that person.", "A production process involving machinery that is not controlled by a person but usually controlled by a computer.", "A method used in flow production where a product moves along a conveyor belt and workers or machines complete different tasks at each stage."]}'::jsonb, '{"answer": 2, "explain": "“Automation” means: A production process involving machinery that is not controlled by a person but usually controlled by a computer."}'::jsonb),
('business:4-1-production-processes:match:d67fab5b', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Robotics”?", "options": ["A product made to the exact individual specification of a customer — unique to that person.", "A method used in flow production where a product moves along a conveyor belt and workers or machines complete different tasks at each stage.", "The use of robots in the process of production.", "Reductions in the average cost per unit that a large business benefits from by producing in very large quantities."]}'::jsonb, '{"answer": 2, "explain": "“Robotics” means: The use of robots in the process of production."}'::jsonb),
('business:4-1-production-processes:match:0096a66a', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Bespoke”?", "options": ["A method used in flow production where a product moves along a conveyor belt and workers or machines complete different tasks at each stage.", "Reductions in the average cost per unit that a large business benefits from by producing in very large quantities.", "A product made to the exact individual specification of a customer — unique to that person.", "When a worker loses their job because their role no longer exists, often because technology has replaced it."]}'::jsonb, '{"answer": 2, "explain": "“Bespoke” means: A product made to the exact individual specification of a customer — unique to that person."}'::jsonb),
('business:4-1-production-processes:match:e187fc06', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Assembly Line”?", "options": ["Reductions in the average cost per unit that a large business benefits from by producing in very large quantities.", "A method used in flow production where a product moves along a conveyor belt and workers or machines complete different tasks at each stage.", "When a worker loses their job because their role no longer exists, often because technology has replaced it.", "The cost of producing one item. Calculated by dividing total costs by the number of units produced."]}'::jsonb, '{"answer": 1, "explain": "“Assembly Line” means: A method used in flow production where a product moves along a conveyor belt and workers or machines complete different tasks at each stage."}'::jsonb),
('business:4-1-production-processes:match:f89e6f3b', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Economies of Scale”?", "options": ["Reductions in the average cost per unit that a large business benefits from by producing in very large quantities.", "When a worker loses their job because their role no longer exists, often because technology has replaced it.", "The cost of producing one item. Calculated by dividing total costs by the number of units produced.", "Another term for flow production — producing very large quantities of a standardised product continuously on an assembly line."]}'::jsonb, '{"answer": 0, "explain": "“Economies of Scale” means: Reductions in the average cost per unit that a large business benefits from by producing in very large quantities."}'::jsonb),
('business:4-1-production-processes:match:16229dbd', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Redundancy”?", "options": ["The cost of producing one item. Calculated by dividing total costs by the number of units produced.", "Another term for flow production — producing very large quantities of a standardised product continuously on an assembly line.", "When a worker loses their job because their role no longer exists, often because technology has replaced it.", "The three methods or processes of production: job, batch, and flow."]}'::jsonb, '{"answer": 2, "explain": "“Redundancy” means: When a worker loses their job because their role no longer exists, often because technology has replaced it."}'::jsonb),
('business:4-1-production-processes:match:fc7a8267', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Unit Cost”?", "options": ["Another term for flow production — producing very large quantities of a standardised product continuously on an assembly line.", "The three methods or processes of production: job, batch, and flow.", "The cost of producing one item. Calculated by dividing total costs by the number of units produced.", "The process of production where products are made individually."]}'::jsonb, '{"answer": 2, "explain": "“Unit Cost” means: The cost of producing one item. Calculated by dividing total costs by the number of units produced."}'::jsonb),
('business:4-1-production-processes:match:37fe8025', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Mass Production”?", "options": ["Another term for flow production — producing very large quantities of a standardised product continuously on an assembly line.", "The three methods or processes of production: job, batch, and flow.", "The process of production where products are made individually.", "The process of production where one type of product is made and then production is switched to make a different product."]}'::jsonb, '{"answer": 0, "explain": "“Mass Production” means: Another term for flow production — producing very large quantities of a standardised product continuously on an assembly line."}'::jsonb),
('business:4-1-production-processes:match:40c763a0', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Production Processes”?", "options": ["The process of production where products are made individually.", "The process of production where one type of product is made and then production is switched to make a different product.", "Production of one product that takes place continuously using a production or assembly line. Also called mass production.", "The three methods or processes of production: job, batch, and flow."]}'::jsonb, '{"answer": 3, "explain": "“Production Processes” means: The three methods or processes of production: job, batch, and flow."}'::jsonb),
('business:4-2-quality-of-goods-services:exam:2b63e82f', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'exam', 'mcq', 1, '{"num": "Q2", "question": "Which of the following would help Zayn deal with this problem?", "options": ["Giving a bonus to the employee who sews the most gloves each month", "Improving quality checks to ensure every glove heats up correctly", "Researching other types of heated clothing that the business could make", "Segmenting the market by age, gender and lifestyle"], "caseStudy": "Zayn is the owner of an established business that makes heated gloves. The business has recently experienced an increase in product returns.", "hint": "Product returns = a quality problem. Which option directly addresses why the gloves are being returned?", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Correct Answer: B — Improving quality checks to ensure every glove heats up correctly</strong></p><p>An increase in returns means the product is failing to meet customer expectations. Improving quality checks addresses the root cause of the problem.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Bonus for most gloves sewn:</strong> Incentivising speed may actually worsen quality, as workers rush production to earn more. Does not address the heating fault.</li><li><strong>C — Researching other heated clothing:</strong> This is a product development strategy, not a solution to the current quality problem with the gloves.</li><li><strong>D — Market segmentation:</strong> This is a marketing activity. Segmenting the market does not fix the fault that is causing gloves to be returned.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-2-quality-of-goods-services:exam:f1e3017f', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'exam', 'mcq', 1, '{"num": "Q5", "question": "Which of the following actions would help QT Homeware Ltd deal with this problem?", "options": ["Include a cloth to wipe up any leaks in the box of all new kettles", "Launch a promotional campaign in a housekeeping magazine", "Meet with production workers to discuss how to reduce costs", "Physically test every hundredth kettle to ensure it is watertight"], "caseStudy": "QT Homeware Ltd manufactures small kitchen appliances. The company has recently received a number of emails complaining that its kettles leak.", "hint": "The problem is that kettles are leaking — a quality problem. Which option actually fixes the quality of the product?", "starter": "The correct answer is D because..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO2 Problem Solving)</h5><p><strong>Correct Answer: D — Physically test every hundredth kettle to ensure it is watertight</strong></p><p>This is a quality control measure that directly addresses the manufacturing fault.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Include a cloth:</strong> This accepts the fault and asks customers to deal with it — it does not solve the quality problem.</li><li><strong>B — Promotional campaign:</strong> Marketing does not fix a manufacturing defect. It may actually damage the brand further if new customers receive leaking kettles.</li><li><strong>C — Meeting to reduce costs:</strong> Cost reduction is unrelated to solving the leaking kettle problem and may make quality worse if it means cutting corners.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-2-quality-of-goods-services:exam:e86c12d8', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'exam', 'mcq', 1, '{"num": "Q6", "question": "The concept of ''quality'' requires a business to:", "options": ["Produce goods that are better than the competition", "Produce goods that are reasonably priced", "Provide services that are fit for purpose", "Provide services that are value for money"], "hint": "What is the official definition of quality? Think about what ''quality'' actually means in a business context.", "starter": "The correct answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1a)</h5><p><strong>Correct Answer: C — Provide services that are fit for purpose</strong></p><p>\"Fit for purpose\" is the core definition of quality — a product or service meets its intended function and the expectations of the customer.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Better than competition:</strong> Quality does not require being better than competitors — just meeting customer expectations at the required standard.</li><li><strong>B — Reasonably priced:</strong> Price is not part of the definition of quality. A cheap product can be quality; an expensive one can fail to be quality.</li><li><strong>D — Value for money:</strong> Value for money is a pricing/marketing concept. Quality means fit for purpose, not necessarily that the customer paid a fair price.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-2-quality-of-goods-services:exam:d84e9287', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Which of the following would be an example of a quality assurance activity for a car manufacturer?", "options": ["Driving every tenth car to test that the brakes are working correctly", "Holding a meeting with production operatives on how to improve the manufacturing process", "Increasing the amount of money that the operations function can spend", "Visually inspecting two cars of each colour for defects in the paintwork"], "hint": "Quality assurance involves all workers improving quality together — it is not about inspecting finished products.", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1b)</h5><p><strong>Correct Answer: B — Holding a meeting with production operatives on how to improve the manufacturing process</strong></p><p>Quality assurance involves all workers in a whole-business approach to quality. Meetings where production workers suggest improvements is a classic QA activity.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Driving every tenth car:</strong> This is quality CONTROL — sampling finished goods to inspect them.</li><li><strong>C — Increasing budget:</strong> This is a financial/resource decision, not a quality method.</li><li><strong>D — Visually inspecting two cars:</strong> This is quality CONTROL — inspecting a sample of finished goods for defects.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-2-quality-of-goods-services:exam:205712cd', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'exam', 'mcq', 1, '{"num": "Q9", "question": "The concept of ''quality'' refers to making products:", "options": ["By hand", "Of a satisfactory standard", "That are better than the leading brand", "To the highest possible specification"], "hint": "What does the official definition of quality say? Think about fit for purpose and meeting customer expectations.", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1a)</h5><p><strong>Correct Answer: B — Of a satisfactory standard</strong></p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — By hand:</strong> The method of production (hand-made vs machine-made) does not determine quality. A machine-made product can absolutely be quality if it is fit for purpose.</li><li><strong>C — Better than the leading brand:</strong> Quality means meeting expectations, not surpassing the market leader.</li><li><strong>D — Highest possible specification:</strong> Quality does not require the highest specification — only a satisfactory one that meets what the customer expected for that product and price.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-2-quality-of-goods-services:exam:3441ceaa', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'exam', 'mcq', 1, '{"num": "Q10", "question": "The concept of quality requires a business to:", "options": ["Charge low prices for its services", "Produce the best goods on the market", "Provide services to required standards", "Source its raw materials from ethical suppliers"], "hint": "Focus on the official definition of quality — it is about standards and meeting expectations, not about price or ethics.", "starter": "The correct answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1b)</h5><p><strong>Correct Answer: C — Provide services to required standards</strong></p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Charge low prices:</strong> Price strategy has nothing to do with the definition of quality.</li><li><strong>B — Produce the best goods:</strong> Quality requires meeting required standards, not necessarily being the best on the market.</li><li><strong>D — Ethical suppliers:</strong> Ethical sourcing is a CSR/sustainability decision. It is not part of the core definition of quality.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-2-quality-of-goods-services:exam:1d69fee3', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'exam', 'mcq', 1, '{"num": "Q12", "question": "What key business function does Sabena perform?", "options": ["After sales service", "Quality control", "Setting production levels", "Supply chain management"], "caseStudy": "Sabena works for a small business that makes computers. Her main task is to test every computer before it leaves the factory.", "hint": "Sabena tests products BEFORE they reach the customer. Which business function describes checking product quality at the end of production?", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1b)</h5><p><strong>Correct Answer: B — Quality control</strong></p><p>Sabena tests every finished computer before it leaves the factory — this is quality control (inspecting finished goods to ensure they meet the required standard before reaching the customer).</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — After sales service:</strong> This would involve helping customers after they have already bought and received the product (e.g. repairs, customer complaints).</li><li><strong>C — Setting production levels:</strong> This is an operations management decision about output volume — unrelated to quality testing.</li><li><strong>D — Supply chain management:</strong> This involves managing suppliers and the flow of materials — nothing to do with testing finished products.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-2-quality-of-goods-services:exam:8b61e72a', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'exam', 'mcq', 1, '{"num": "Q15", "question": "A manufacturer makes chocolate bars. All of the chocolate bars are passed through a machine to check for production mistakes before being boxed. This is an example of:", "options": ["Product development", "Product recall", "Quality assurance", "Quality control"], "hint": "Is this preventing mistakes or checking for them after they''ve been made? Which quality method involves inspection at the end of production?", "starter": "The correct answer is D because..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1b)</h5><p><strong>Correct Answer: D — Quality control</strong></p><p>All finished chocolate bars are inspected by a machine before being boxed — this is a classic quality control system (checking finished goods to ensure they meet the required standard before reaching the customer).</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Product development:</strong> This refers to creating or improving products, not to checking their quality.</li><li><strong>B — Product recall:</strong> A recall happens after products have been sold and a fault is found. This inspection happens before the product leaves the factory.</li><li><strong>C — Quality assurance:</strong> QA would involve ALL workers taking responsibility for preventing mistakes throughout production — not just a machine inspecting at the end. The key distinction: QA prevents, QC checks.</li></ul><p><strong>⚠️ Examiner''s Comment:</strong> There was a clear misunderstanding between quality control and quality assurance. These are technical terms that must be understood precisely. Key term revision — lists, flashcards, and mini tests — can prevent these errors.</p></div>", "modelAnswer": ""}'::jsonb),
('business:4-2-quality-of-goods-services:mcq:00a0c9cd', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'mcq', 'mcq', 1, '{"question": "Which of the following best describes the concept of ''quality'' for a business?", "options": ["Producing goods that are more expensive than those of competitors", "Producing goods or services that are fit for purpose and meet customer expectations", "Using only the highest-grade raw materials regardless of cost", "Ensuring all products outperform the market leader"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Quality means a product or service is fit for purpose, meets legal requirements, and meets customer expectations — not about being the most expensive or most luxurious. Option A confuses quality with premium pricing. Options C and D describe standards that exceed what quality requires."}'::jsonb),
('business:4-2-quality-of-goods-services:mcq:2afc4e16', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'mcq', 'mcq', 1, '{"question": "Which of the following statements best describes quality assurance?", "options": ["Inspectors are used to check the quality of goods being produced", "Only finished goods are checked so no faulty products are sold", "All workers are involved in and responsible for the quality of their work", "Quality is only checked once production is finished so it does not disrupt output"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Quality assurance involves the whole business in maintaining quality — every worker takes personal responsibility at every stage of production. Option A describes quality control (specialist inspectors). Option B describes end-of-line quality control. Option D is false — QA can slow production because workers stop to check their own work."}'::jsonb),
('business:4-2-quality-of-goods-services:mcq:21a5248b', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'mcq', 'mcq', 1, '{"question": "Which of the following is a disadvantage of using quality control?", "options": ["Inspectors do not need to be paid because workers check their own quality", "Inspectors are better at checking the quality of goods than workers", "Workers do not have to disrupt production to check quality", "Inspectors have to be paid for their work, adding to the cost of production"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. Quality control requires specialist inspectors who must be paid a wage, and laboratory testing equipment also has a cost — both add to total production costs. Option A is false (inspectors do need to be paid). Option B is not a disadvantage. Option C is actually an advantage of quality control (production is not disrupted)."}'::jsonb),
('business:4-2-quality-of-goods-services:mcq:6d9578a2', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'mcq', 'mcq', 1, '{"question": "A manufacturer makes chocolate bars. All bars are passed through a machine to check for production mistakes before being boxed. This is an example of:", "options": ["Product development", "Product recall", "Quality assurance", "Quality control"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. This is quality control — a system where finished goods are inspected (by a machine acting as the inspector) before reaching the customer. It is end-of-production checking, not prevention at every stage, so it is NOT quality assurance. Option A (product development) means creating new products. Option B (product recall) means bringing products back after they have been sold."}'::jsonb),
('business:4-2-quality-of-goods-services:mcq:d84e9287', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'mcq', 'mcq', 1, '{"question": "Which of the following would be an example of a quality assurance activity for a car manufacturer?", "options": ["Driving every tenth car to test that the brakes are working correctly", "Holding a meeting with production operatives on how to improve the manufacturing process", "Increasing the amount of money that the operations function can spend", "Visually inspecting two cars of each colour for defects in the paintwork"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Quality assurance involves all workers contributing to improving quality — holding a meeting with production workers to suggest improvements is a classic QA activity (whole-business involvement). Options A and D are quality control examples (sampling and inspection). Option C is a financial/budget decision with no direct link to quality methods."}'::jsonb),
('business:4-2-quality-of-goods-services:mcq:205712cd', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'mcq', 'mcq', 1, '{"question": "The concept of ''quality'' refers to making products:", "options": ["By hand", "Of a satisfactory standard", "That are better than the leading brand", "To the highest possible specification"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Quality means producing goods or services to a satisfactory standard — fit for purpose and meeting customer expectations at the price paid. Option A is wrong (quality can apply to machine-made products). Option C is wrong (quality does not mean being better than competitors). Option D is wrong (the highest possible specification may exceed what customers expect or are willing to pay for)."}'::jsonb),
('business:4-2-quality-of-goods-services:mcq:d81d9960', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'mcq', 'mcq', 1, '{"question": "Zayn owns a business making heated gloves. The business has recently experienced an increase in product returns. Which of the following would best help Zayn deal with this problem?", "options": ["Giving a bonus to the employee who sews the most gloves each month", "Improving quality checks to ensure every glove heats up correctly", "Researching other types of heated clothing the business could make", "Segmenting the market by age, gender and lifestyle"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Product returns indicate a quality problem — gloves are not meeting customer expectations. Improving quality checks (quality control) would catch faulty gloves before they are sold. Option A rewards speed, which may actually make the quality problem worse. Options C and D are unrelated to the quality/returns issue."}'::jsonb),
('business:4-2-quality-of-goods-services:mcq:37601b98', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'mcq', 'mcq', 1, '{"question": "QT Homeware Ltd manufactures small kitchen appliances and has received complaints that its kettles leak. Which action would best help deal with this problem?", "options": ["Include a cloth to wipe up any leaks in the box of all new kettles", "Launch a promotional campaign in a housekeeping magazine", "Meet with production workers to discuss how to reduce costs", "Physically test every hundredth kettle to ensure it is watertight"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. Physically testing kettles to ensure they are watertight is a quality control measure that directly addresses the root cause of the complaints. Option A treats the symptom (leaks) rather than solving the underlying quality fault. Option B is a marketing activity that does not fix the product. Option C focuses on cost reduction, not quality improvement."}'::jsonb),
('business:4-2-quality-of-goods-services:mcq:e915a0e9', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'mcq', 'mcq', 1, '{"question": "Sabena works for a small business that makes computers. Her main task is to test every computer before it leaves the factory. What key business function does Sabena perform?", "options": ["After sales service", "Quality control", "Setting production levels", "Supply chain management"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Sabena inspects every finished computer before it reaches the customer — this is quality control (checking finished goods to ensure they meet the required standard). After-sales service (A) happens after the product is sold and delivered. Setting production levels (C) is an operations management decision. Supply chain management (D) involves managing suppliers and logistics."}'::jsonb),
('business:4-2-quality-of-goods-services:mcq:3441ceaa', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'mcq', 'mcq', 1, '{"question": "The concept of quality requires a business to:", "options": ["Charge low prices for its services", "Produce the best goods on the market", "Provide services to required standards", "Source its raw materials from ethical suppliers"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Quality requires a business to produce goods or services that meet required standards — fit for purpose and meeting customer expectations. Option A (low prices) is about pricing strategy, not quality. Option B (best goods) exceeds what quality requires — being satisfactory is enough. Option D (ethical suppliers) relates to CSR, not the definition of quality."}'::jsonb),
('business:4-2-quality-of-goods-services:mcq:df616cf5', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'mcq', 'mcq', 1, '{"question": "Which of these statements is TRUE about the importance of quality?", "options": ["It is easy to gain a reputation for quality", "It is easy to lose a reputation for quality", "Producing high-quality goods always increases sales", "Producing high quality is always cheaper than producing low quality"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. It is easy to lose a reputation for quality — one product failure or poor customer experience can damage a reputation built over many years. Option A is false: gaining a reputation for quality takes significant time and investment. Option C is false: other factors like price and marketing affect sales. Option D is false: quality production (e.g. better materials, QA training) usually costs more, not less."}'::jsonb),
('business:4-2-quality-of-goods-services:mcq:fa61419f', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'mcq', 'mcq', 1, '{"question": "A pottery business produces 200 vases per week. Each item costs £45. On average, 2 out of every 50 are faulty and must be scrapped. What is the total cost of this wastage in an average week?", "options": ["£9,000", "£180", "£360", "£720"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Step 1 — find the number of faulty vases: 200 ÷ 50 = 4 batches of 50, each with 2 faulty = 4 × 2 = 8 faulty vases. Step 2 — calculate the cost: 8 × £45 = £360. Option A (£9,000) is the total weekly production cost (200 × £45), not the waste cost. Option B (£180) uses the wrong faulty rate. Option D (£720) doubles the correct answer."}'::jsonb),
('business:4-2-quality-of-goods-services:tf:2e57bc80', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tf', 'tf', 1, '{"question": "Quality means a product or service must be the most expensive or best on the market."}'::jsonb, '{"answer": false, "explain": "FALSE. Quality means a product or service is fit for purpose and meets customer expectations at the price paid — not that it must be the most expensive or best available."}'::jsonb),
('business:4-2-quality-of-goods-services:tf:e000f831', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tf', 'tf', 1, '{"question": "In quality assurance, every employee at every stage of production is responsible for quality."}'::jsonb, '{"answer": true, "explain": "TRUE. Quality assurance creates a culture of quality throughout the whole business — it is not just the job of specialist inspectors. This is what distinguishes it from quality control."}'::jsonb),
('business:4-2-quality-of-goods-services:tf:1bd828b6', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tf', 'tf', 1, '{"question": "Quality control prevents waste because faults are caught before resources are used to make defective goods."}'::jsonb, '{"answer": false, "explain": "FALSE. Quality control does NOT prevent waste — it only catches faults after the goods have already been made. The materials and labour used to produce defective items are already wasted by the time they are inspected."}'::jsonb),
('business:4-2-quality-of-goods-services:tf:7f6caeeb', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tf', 'tf', 1, '{"question": "A recall occurs when a business asks customers to return a faulty product so it can be repaired or replaced."}'::jsonb, '{"answer": true, "explain": "TRUE. A recall is when a fault is identified in a product that has already been sold, and the business contacts customers to return it for repair or replacement — as Whirlpool did with its washing machines in 2019."}'::jsonb),
('business:4-2-quality-of-goods-services:tf:668fb396', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tf', 'tf', 1, '{"question": "Quality assurance is non-disruptive to production because workers continue producing while inspectors do the checking."}'::jsonb, '{"answer": false, "explain": "FALSE. This describes quality CONTROL, not quality assurance. Quality assurance can actually disrupt production because workers stop to check the quality of their own work at each stage."}'::jsonb),
('business:4-2-quality-of-goods-services:tf:45962f10', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tf', 'tf', 1, '{"question": "It is easier to lose a reputation for quality than it is to build one."}'::jsonb, '{"answer": true, "explain": "TRUE. Building a reputation for quality takes a long time and requires consistent investment. Losing it can happen very quickly — a single product failure, recall, or viral negative review can damage years of hard-earned reputation."}'::jsonb),
('business:4-2-quality-of-goods-services:tf:10fd269e', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tf', 'tf', 1, '{"question": "Toyota Motors is an example of a business that uses quality control because inspectors check every car at the end of the production line."}'::jsonb, '{"answer": false, "explain": "FALSE. Toyota is associated with quality ASSURANCE — its system involves all employees being responsible for quality at every stage of production and continuously suggesting improvements. This is the opposite of relying solely on end-of-line inspectors."}'::jsonb),
('business:4-2-quality-of-goods-services:tf:336d16c7', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tf', 'tf', 1, '{"question": "A mystery shopper is an example of a quality control method used in service businesses."}'::jsonb, '{"answer": true, "explain": "TRUE. A mystery shopper is a quality control method — a person posing as a customer who checks the service against required standards and reports findings to management, allowing the business to take corrective action."}'::jsonb),
('business:4-2-quality-of-goods-services:tf:fda5907c', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tf', 'tf', 1, '{"question": "One disadvantage of quality assurance is that it may cost a business a lot of money to train workers to assess the quality of their own work."}'::jsonb, '{"answer": true, "explain": "TRUE. Quality assurance requires all workers to be trained to understand quality standards and assess their own work. This training takes time and money — it is a significant cost, particularly for larger businesses with many employees."}'::jsonb),
('business:4-2-quality-of-goods-services:tf:372a7d3d', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tf', 'tf', 1, '{"question": "Quality control is a better method than quality assurance in all situations."}'::jsonb, '{"answer": false, "explain": "FALSE. Neither method is universally better — it depends on the context. Quality control is better suited to highly technical products needing specialist laboratory testing. Quality assurance is better when workers can judge quality themselves and the business wants to build a quality culture and reduce waste."}'::jsonb),
('business:4-2-quality-of-goods-services:tf:db9795fb', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tf', 'tf', 1, '{"question": "Poor quality can lead to disrupted production if faulty materials from an early stage cannot be used in a later stage."}'::jsonb, '{"answer": true, "explain": "TRUE. If materials produced at an early stage in the production process are of insufficient quality, they cannot be passed to the next stage — halting or slowing the entire production line and increasing costs."}'::jsonb),
('business:4-2-quality-of-goods-services:tf:bbbf488f', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tf', 'tf', 1, '{"question": "One advantage of quality control is that it motivates workers by giving them responsibility for quality."}'::jsonb, '{"answer": false, "explain": "FALSE. This is an advantage of quality ASSURANCE, not quality control. In quality control, workers simply produce goods — inspectors do the checking. It is quality assurance that motivates workers by giving them personal responsibility and making them feel valued."}'::jsonb),
('business:4-2-quality-of-goods-services:learn:80847ddf', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>These are the essential terms you <strong>must</strong> know for this topic. Examiners award no credit for vague or imprecise definitions — learn these word-for-word.</p>\n<ul>\n  <li><strong>Quality:</strong> A product or service that is <strong>fit for purpose</strong> — it does what it is supposed to do, meets legislative rules (e.g. design and safety regulations), and meets <strong>customer expectations</strong>.</li>\n  <li><strong>Quality Control:</strong> A system for <strong>inspecting</strong> the quality of goods or services produced to ensure they are of a good standard. Checking is typically carried out by specialist inspectors at the end of, or during, production.</li>\n  <li><strong>Quality Assurance:</strong> An approach that involves the <strong>whole business</strong> focusing on quality, aiming to <strong>prevent</strong> quality problems from arising. Every employee at every stage of production is responsible for quality.</li>\n  <li><strong>Returns:</strong> Goods which customers take back to the shop because there are problems with the quality of them.</li>\n  <li><strong>Recalls:</strong> When a fault occurs with a product and the business asks for the product to be brought back so it can be repaired or replaced (e.g. Whirlpool washing machines in 2019).</li>\n  <li><strong>Mystery Shopper:</strong> A person who pretends to be a normal customer but secretly evaluates whether the service provided meets the required standard.</li>\n  <li><strong>Fit for Purpose:</strong> A product or service that fulfils its intended function and meets the reasonable expectations of the customer at the price they paid.</li>\n</ul>", "question": "According to the official definition, quality assurance is best described as...?", "options": ["Every employee preventing quality problems at every stage", "Specialist inspectors checking finished goods at the end", "A promise that a product is the most expensive", "A process only used to identify recalls after sale"]}'::jsonb, '{"answer": 0, "explain": "Quality assurance is a whole-business approach where every employee is responsible for quality at every stage, aiming to prevent problems rather than just catch them."}'::jsonb),
('business:4-2-quality-of-goods-services:learn:904f82da', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'learn', 'mcq', 1, '{"readingTitle": "The Concept of Quality", "reading": "<p>Quality does <strong>not</strong> mean the most expensive or the best product on the market. A product or service is considered quality when it meets <strong>three criteria</strong>:</p>\n<ul>\n  <li><strong>Fit for purpose</strong> — it does what it is supposed to do</li>\n  <li><strong>Meets legislative rules</strong> — complies with design and safety regulations</li>\n  <li><strong>Meets customer expectations</strong> — even a cheap product can be quality if it does what the customer expected when buying it at that price point</li>\n</ul>\n<p>⚠️ <strong>Key Examiner Insight:</strong> Quality is about <em>meeting expectations</em>, not luxury. A budget supermarket own-brand tin of beans is quality if it tastes acceptable and the tin seals correctly. A £500 designer handbag that falls apart is <em>not</em> quality. This distinction comes up constantly in exam questions.</p>\n<p>The saying <strong>\"It costs five times more to gain a customer than to keep a customer\"</strong> highlights why quality matters strategically. Losing a customer through poor quality is easy — winning them back (or finding new ones) requires costly marketing campaigns.</p>\n<div class=\"case-study-box\">\n  <h4>Case Study: The Holiday Park (Tripadvisor)</h4>\n  <p>Online review platforms like Tripadvisor allow customers to share experiences publicly. A negative review describing a dirty caravan, broken TV, and rude staff can be read by thousands of potential customers — devastating a business''s bookings overnight. This illustrates how a failure to meet customer quality expectations directly translates into lost revenue and lasting reputational damage.</p>\n</div>", "question": "Which of these best illustrates the key examiner insight about quality described in this card?", "options": ["A budget tin of beans that tastes acceptable and seals correctly for its price", "Only premium products that are bought by customers at a high price", "A product that costs the business the most money to manufacture", "A product that is manufactured using the most advanced automated machinery"]}'::jsonb, '{"answer": 0, "explain": "The card stresses that quality is about meeting expectations at the price paid, not about luxury — a cheap product can be quality, and an expensive one can fail to be."}'::jsonb),
('business:4-2-quality-of-goods-services:learn:caa11d68', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'learn', 'mcq', 1, '{"readingTitle": "The Importance of Quality", "reading": "<p>There are four key consequences of <strong>poor quality</strong> that a business must avoid:</p>\n<ul>\n  <li><strong>Avoids Waste:</strong> Poor-quality goods cannot be sold at full price (or must be sold cheaply as ''seconds''). The business has already spent money on materials and labour — those resources are wasted. Customer returns also cost money to process and replace.</li>\n  <li><strong>Avoids Recalls:</strong> If a safety fault is discovered after products are already sold, the business must recall them. This is hugely expensive — involving engineer visits, repair costs, compensation payments, and severe reputational damage.</li>\n  <li><strong>Reputation and Sales:</strong> Customers who receive poor-quality goods or services may buy from a competitor in future, tell friends and family, or post negative reviews online. A poor reputation is extremely difficult and expensive to reverse — the business loses both existing and potential new customers.</li>\n  <li><strong>Disrupted Production:</strong> If components produced early in the production process are faulty, they cannot be used in later stages — shutting down or slowing the entire production line and increasing unit costs.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Whirlpool Recalls (2019–2020)</h4>\n  <p>In 2019, Whirlpool identified 519,000 Indesit and Hotpoint washing machines at risk of fire due to a door lock fault (machines made 2014–2018). Engineers had to visit every affected customer''s home for free. In 2020, a further 55,000 machines were recalled. Earlier, 5 million tumble dryers had also been recalled — some caused actual fires. In 2016, 50 residents at Shepherds Court, London, needed alternative accommodation after a fire caused by a Whirlpool tumble dryer. The company paid compensation to all affected residents. This case illustrates the catastrophic financial and reputational cost of quality failure on a large scale.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Customer Service Research (Opinium, 2020)</h4>\n  <p>A survey of 2,000 UK consumers found 79% had experienced bad customer service. Of these, 54% said they would not return to a business after poor service — costing the UK economy an estimated £2.5 billion in lost sales annually. The top-rated businesses during the pandemic were Tesco, Asda, and M&S — all of which adapted quickly to meet changed customer needs.</p>\n</div>", "question": "How many Indesit and Hotpoint washing machines did Whirlpool identify as at risk of fire in its 2019 recall?", "options": ["519,000", "55,000", "5 million", "2,000"]}'::jsonb, '{"answer": 0, "explain": "The case study states Whirlpool identified 519,000 washing machines made 2014–2018 as at risk of fire due to a door lock fault."}'::jsonb),
('business:4-2-quality-of-goods-services:learn:928f665d', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'learn', 'mcq', 1, '{"readingTitle": "Quality Control — How It Works", "reading": "<p><strong>Quality control</strong> is about <em>checking</em> that a product or service meets required standards. It catches defects but does <strong>not prevent them from happening</strong> in the first place — that is the key distinction from quality assurance.</p>\n<p>Methods used in quality control:</p>\n<ul>\n  <li><strong>Physical inspection:</strong> Specialist inspectors sample raw materials, goods during manufacture, or finished products. Some items are tested in a laboratory (e.g. pharmaceutical drugs, food products).</li>\n  <li><strong>Automated machine checks:</strong> Machinery programmed to detect faults automatically ejects items that fail to meet standards — no human inspector required for that stage.</li>\n  <li><strong>Mystery shopper:</strong> A paid individual poses as a normal customer and covertly scores the service on categories such as staff helpfulness, facilities, speed, and product quality. A written report is sent to management for action.</li>\n  <li><strong>Customer satisfaction surveys:</strong> Customers rate their experience after purchase. The business uses the data to identify recurring problems and make targeted improvements.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Heinz Beanz — Automated Quality Control</h4>\n  <p>The Heinz Beanz factory in Wigan produces approximately 3 million cans every day using a highly automated process. Machinery is programmed to detect faults in cans or labels. If a can is the wrong weight or has not been properly sealed, it is automatically ejected from the production line before it can be sold to customers. This is a textbook example of quality control using technology — faults are caught at the end of production rather than prevented at source.</p>\n</div>", "question": "In the Heinz Beanz case study, approximately how many cans does the Wigan factory produce each day?", "options": ["3 million", "500,000", "50,000", "10 million"]}'::jsonb, '{"answer": 0, "explain": "The Heinz Beanz factory in Wigan produces approximately 3 million cans every day using a highly automated quality control process."}'::jsonb),
('business:4-2-quality-of-goods-services:learn:05809be5', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'learn', 'mcq', 1, '{"readingTitle": "Quality Control — Advantages & Disadvantages", "reading": "<p>Use this two-column layout to evaluate quality control in exam answers:</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Prevents faulty goods reaching customers:</strong> Inspection catches defects before products leave the factory, reducing the number of returns and recalls.</div>\n    <div class=\"pro-item\"><strong>Non-disruptive to production:</strong> Workers continue producing while specialist inspectors do the checking — the production line does not need to stop, keeping output levels high.</div>\n    <div class=\"pro-item\"><strong>Improved reputation:</strong> Consistently meeting quality standards builds consumer confidence, which can increase repeat purchases and attract new customers.</div>\n    <div class=\"pro-item\"><strong>Suitable for technical products:</strong> Products like pharmaceutical drugs or chemicals require specialist laboratory testing that workers could not carry out themselves — quality control is the only viable approach here.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>Does not prevent waste:</strong> Faulty goods are only discovered after they have already been made — the materials and labour used to produce them are wasted, increasing costs.</div>\n    <div class=\"con-item\"><strong>Costly inspection process:</strong> The business must pay inspectors'' wages and fund the cost of testing equipment or laboratory analysis, adding to total production costs.</div>\n    <div class=\"con-item\"><strong>Workers not responsible for quality:</strong> Because inspectors do the checking, ordinary workers have no personal ownership of quality standards — this can reduce care and vigilance on the production line.</div>\n    <div class=\"con-item\"><strong>May miss faults:</strong> If only a sample of products are inspected, some faulty items may pass through undetected and reach customers.</div>\n  </div>\n</div>", "question": "Which of these is listed as a disadvantage of quality control?", "options": ["Workers have less personal responsibility for quality", "Production stops while workers check their own work", "It needs extensive training for every employee", "It builds a culture of continuous improvement"]}'::jsonb, '{"answer": 0, "explain": "Because inspectors do the checking under quality control, ordinary workers have no personal ownership of quality standards, which can reduce care and vigilance."}'::jsonb),
('business:4-2-quality-of-goods-services:learn:a724c87e', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'learn', 'mcq', 1, '{"readingTitle": "Quality Assurance — How It Works", "reading": "<p><strong>Quality assurance</strong> is about <em>preventing</em> quality problems before they arise. It creates a <strong>culture of quality</strong> throughout the whole organisation — not just in a dedicated inspection department.</p>\n<p>Key features of quality assurance:</p>\n<ul>\n  <li><strong>Every employee is involved</strong> at every stage of the production process — this is sometimes called Total Quality Management (TQM).</li>\n  <li>Each worker treats the <strong>next person in the production process as their internal customer</strong> — they must be satisfied with the quality of what has been passed to them.</li>\n  <li>Employees are <strong>encouraged to suggest improvements</strong> — regular meetings at all levels focus on continuous improvement.</li>\n  <li>Quality is <strong>built into the process</strong> from the start, rather than checked at the end.</li>\n  <li>Products and services are designed with consumer needs at the centre from the outset.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Toyota Motors — Quality Assurance in Manufacturing</h4>\n  <p>Toyota is perhaps the company most closely associated with quality assurance. Its system stresses <em>continuous improvement</em> (''kaizen'') and requires every employee to suggest improvements and take personal responsibility for the quality of their own work. Toyota aims to reduce waste at every stage and produce cars that precisely meet customer needs. Its two core principles are ''customer first'' and ''respect for people''.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Disney World, Florida — Quality Assurance in Services</h4>\n  <p>Disney World applies quality assurance to a service business. All employees — from actors in parades to street cleaners — are called ''cast members''. The entire visitor experience is treated as a ''show'' that every worker contributes to. Each cast member is personally responsible for delivering high-quality service at all times, ensuring every customer has a great experience. This shows that quality assurance is just as relevant to service industries as it is to manufacturing.</p>\n</div>", "question": "What are Toyota''s two core principles, according to the case study in this card?", "options": ["Customer first and respect for people", "Speed and efficiency", "Cost reduction and automation", "Innovation and profit maximisation"]}'::jsonb, '{"answer": 0, "explain": "The case study states Toyota''s two core principles are ''customer first'' and ''respect for people'', which underpin its continuous-improvement (''kaizen'') approach to quality assurance."}'::jsonb),
('business:4-2-quality-of-goods-services:learn:3f8feeda', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'learn', 'mcq', 1, '{"readingTitle": "Quality Assurance — Advantages & Disadvantages", "reading": "<p>Use this two-column layout when evaluating quality assurance in exam answers:</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Reduces wastage and costs:</strong> Because quality is checked at every stage, faults are caught early before more resources are invested in a defective product — reducing production costs.</div>\n    <div class=\"pro-item\"><strong>Motivates workers:</strong> Employees feel valued and trusted when given personal responsibility for quality. This can increase effort, engagement, and output quality.</div>\n    <div class=\"pro-item\"><strong>Improved reputation:</strong> A whole-business focus on quality builds a consistent, strong reputation over time, which attracts and retains customers and may allow the business to charge higher prices.</div>\n    <div class=\"pro-item\"><strong>Fewer returns and recalls:</strong> Catching problems during production means fewer defective products ever reach customers — saving the cost of returns, recalls, and compensation payments.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>May disrupt production:</strong> Workers stopping to check their own work slows down the production line, potentially reducing output per hour and raising the cost per unit.</div>\n    <div class=\"con-item\"><strong>High training costs:</strong> Workers need extensive training to assess and take responsibility for quality standards — this requires significant investment in time and HR resources.</div>\n    <div class=\"con-item\"><strong>Worker resistance:</strong> Some employees may be uncomfortable with the added pressure of responsibility for quality and may resist the introduction of QA methods — potentially causing conflict or lower morale.</div>\n    <div class=\"con-item\"><strong>Not suitable for all products:</strong> Highly technical products such as pharmaceutical drugs still require specialist laboratory testing that ordinary production workers cannot perform, regardless of QA procedures.</div>\n  </div>\n</div>", "question": "According to this card, which type of product still requires specialist laboratory testing even under quality assurance?", "options": ["Pharmaceutical drugs", "Own-brand tinned beans", "Bicycles", "Washing machines"]}'::jsonb, '{"answer": 0, "explain": "The card notes that highly technical products such as pharmaceutical drugs still require specialist laboratory testing that ordinary production workers cannot perform, regardless of QA procedures."}'::jsonb),
('business:4-2-quality-of-goods-services:learn:2a8b954b', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'learn', 'mcq', 1, '{"readingTitle": "Quality Control vs Quality Assurance — Evaluation", "reading": "<p>When a question asks you to evaluate or recommend a quality method, always consider the <strong>context</strong> — the type of product, the business''s size, and the specific problem being faced.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">Use Quality Control when...</div>\n    <div class=\"pro-item\">The product is highly technical and requires specialist lab testing (e.g. drugs, chemicals, food safety checks)</div>\n    <div class=\"pro-item\">The business needs production to run without interruption — workers focus on output, inspectors on quality</div>\n    <div class=\"pro-item\">Automated machinery can perform checks efficiently at high speed (e.g. Heinz Beanz production line)</div>\n  </div>\n  <div>\n    <div class=\"col-head\">Use Quality Assurance when...</div>\n    <div class=\"pro-item\">The workforce is skilled enough to judge and take responsibility for their own work (e.g. car manufacturing at Toyota)</div>\n    <div class=\"pro-item\">The business wants to reduce waste at source rather than discover it at the end of production</div>\n    <div class=\"pro-item\">The business operates in the service sector and wants all staff personally invested in customer experience (e.g. Disney World)</div>\n  </div>\n</div>\n<p><strong>Key evaluation point for high-mark answers:</strong> Building a reputation for quality takes a <em>long time</em>. Losing it can happen <em>very quickly</em>. A business that invests in either quality method protects itself from the costs of waste, returns, recalls, and customer loss. However, the method must match the business context — there is no single ''right'' answer.</p>\n<p><strong>The ''It depends on...'' rule:</strong> In a 6–9 mark evaluation, always qualify your recommendation. For example: \"Quality assurance would be more beneficial for ABC Bicycles because it reduces waste, but this depends on whether the business can afford the significant training costs involved.\"</p>", "question": "According to this evaluation card, when should a business use quality assurance rather than quality control?", "options": ["When the workforce is skilled enough to take responsibility for quality", "When the product requires specialist lab testing, such as drugs or chemicals", "When production must run continuously without any interruption at all", "When automated machinery can perform checks at high speed and scale"]}'::jsonb, '{"answer": 0, "explain": "The card states quality assurance suits businesses where the workforce is skilled enough to judge and take responsibility for their own work, using Toyota as the example."}'::jsonb),
('business:4-2-quality-of-goods-services:misc:6677d777', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Quality means a product is expensive, luxurious, or the best on the market.</p><p><strong>✅ The correct idea:</strong> Quality means a product or service is fit for purpose and meets customer expectations at the price paid. A cheap product can be ''quality'' if it does what the customer expected. An expensive product that fails is not quality.</p>", "question": "What does ''quality'' actually mean in this topic, according to the correct explanation?", "options": ["Fit for purpose, meeting customer expectations at the price paid", "Priced higher than every rival product currently on the market", "Packaged in the most luxurious box available on the market", "Manufactured and sold under a well-known, trusted brand name"]}'::jsonb, '{"answer": 0, "explain": "The card corrects the misconception that quality means expensive or luxurious — quality actually means fit for purpose and meeting customer expectations at the price paid."}'::jsonb),
('business:4-2-quality-of-goods-services:misc:0415aa49', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Quality control and quality assurance are the same thing — both involve checking goods.</p><p><strong>✅ The correct idea:</strong> They are fundamentally different. Quality CONTROL uses specialist inspectors to check products, usually at the end of production. Quality ASSURANCE involves ALL workers being responsible for quality throughout the entire production process, aiming to PREVENT faults rather than just catch them.</p>", "question": "What is the key difference between quality control and quality assurance, according to this card?", "options": ["Quality control uses inspectors to check goods, while quality assurance involves all workers", "Quality control and quality assurance are simply two different names for the same process", "Quality assurance only checks finished goods once, right at the very end of production", "Quality control involves every single worker checking their own work at every stage"]}'::jsonb, '{"answer": 0, "explain": "Quality control relies on specialist inspectors checking products, usually at the end of production, while quality assurance makes all workers responsible for preventing faults throughout production."}'::jsonb),
('business:4-2-quality-of-goods-services:misc:5a7718d0', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Quality assurance does not disrupt production because quality is only checked once production is finished.</p><p><strong>✅ The correct idea:</strong> The opposite is true. Quality ASSURANCE can disrupt production because workers stop to check their own work at each stage. It is quality CONTROL that does NOT disrupt production, because workers continue producing while inspectors check.</p>", "question": "Which quality method actually disrupts production, according to this card?", "options": ["Quality assurance, since workers pause to check their own work", "Quality control, because inspectors slow down the entire production line", "Neither method causes any real disruption to production at all", "Both methods disrupt production by roughly the same amount"]}'::jsonb, '{"answer": 0, "explain": "It is quality assurance that can disrupt production, since workers stop to check their own work at each stage — quality control does not disrupt production because inspectors check while workers keep producing."}'::jsonb),
('business:4-2-quality-of-goods-services:misc:661ae5d5', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Quality control prevents waste because it catches faulty goods.</p><p><strong>✅ The correct idea:</strong> Quality control does NOT prevent waste — the materials and labour to make a faulty product have already been used up before the inspector finds the fault. Quality ASSURANCE reduces waste because faults are caught early, before more resources are spent on a defective item.</p>", "question": "Why does quality control NOT prevent waste, according to this card?", "options": ["Because materials and labour are already used up before a fault is found", "Because inspectors are simply too slow to catch every single fault", "Because quality control is only ever used within service industries", "Because quality control checks products only before they are manufactured"]}'::jsonb, '{"answer": 0, "explain": "Quality control only catches faults after production, so the materials and labour used to make a faulty product have already been wasted by the time an inspector finds the fault."}'::jsonb),
('business:4-2-quality-of-goods-services:misc:0920bf40', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For a 1-mark ''identify'' question about quality, writing ''suppliers'' is enough for a mark.</p><p><strong>✅ The correct idea:</strong> Examiners require a specific, precise answer. ''Suppliers'' alone is too vague. The correct answer would be ''the quality of raw materials / supplies used.'' Always be specific about WHAT about suppliers affects quality.</p>", "question": "For a 1-mark identify question on factors affecting quality, why would writing just ''suppliers'' score 0 marks?", "options": ["It is too vague — it doesn''t state what about suppliers affects quality", "Suppliers are never considered a relevant factor affecting product quality", "The examiner only accepts answers that mention staff training", "It should have been written out as a full paragraph instead"]}'::jsonb, '{"answer": 0, "explain": "Examiners require a specific, precise answer such as ''the quality of raw materials/supplies used'' — simply writing ''suppliers'' is too vague to earn the mark."}'::jsonb),
('business:4-2-quality-of-goods-services:misc:b7c151a6', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For a 3-mark analyse question, writing everything you know about quality control will get full marks.</p><p><strong>✅ The correct idea:</strong> This is ''knowledge dumping'' and will score 0 for analysis. You MUST follow the U → APP → AN structure: explain the concept (U), link it specifically to the business in the case study (APP), then explain the financial or operational impact on that business (AN).</p>", "question": "Why would ''writing everything you know about quality control'' fail to score marks on a 3-mark analyse question?", "options": ["Because it is knowledge dumping, which scores 0 for analysis marks", "Because analyse questions are marked purely on handwriting neatness", "Because 3-mark questions only ever accept bullet-point style answers", "Because analyse questions never actually require any real understanding"]}'::jsonb, '{"answer": 0, "explain": "Knowledge dumping without following the U → APP → AN structure (explain, apply to the case study business, then analyse impact) scores 0 for analysis."}'::jsonb),
('business:4-2-quality-of-goods-services:misc:b5ea4979', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A product recall is the same as a product return.</p><p><strong>✅ The correct idea:</strong> These are different. A RETURN is when an individual customer brings back a faulty product to the shop. A RECALL is when the business itself identifies a serious fault and proactively contacts all affected customers to return the product for repair or replacement.</p>", "question": "What is the difference between a ''return'' and a ''recall'', according to this card?", "options": ["A return is customer-led; a recall is business-led", "A recall only ever happens to service businesses", "A return and a recall are the same process", "A recall always costs less than a return"]}'::jsonb, '{"answer": 0, "explain": "A return is when an individual customer brings a faulty product back; a recall is when the business itself identifies a fault and proactively contacts affected customers."}'::jsonb),
('business:4-2-quality-of-goods-services:misc:5c5a1e14', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Quality assurance only applies to manufacturing businesses.</p><p><strong>✅ The correct idea:</strong> Quality assurance applies equally to service businesses. Disney World is a classic example — all ''cast members'' (staff) take personal responsibility for delivering a high-quality customer experience, which is quality assurance applied to a service.</p>", "question": "Which case study is used to show that quality assurance applies to service businesses too?", "options": ["Disney World, where ''cast members'' take responsibility for customer experience", "Heinz Beanz, where automated machines eject cans that fail inspection", "ABC Bicycles, where specialist inspectors check the quality of each bike", "Whirlpool, where faulty washing machines were recalled from customers'' homes"]}'::jsonb, '{"answer": 0, "explain": "Disney World is used as the example of quality assurance in a service business, where all ''cast members'' take personal responsibility for delivering high-quality customer experience."}'::jsonb),
('business:4-2-quality-of-goods-services:tips:ba412703', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1 mark — One Specific Point. That Is All.", "reading": "\n      <p>A 1-mark <strong>''Identify'' or ''State''</strong> question needs exactly one correct, specific point. Nothing more. Do not write a paragraph, do not define the term, do not give an example unless asked.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>One clear, specific point = 1 mark ✅</li>\n        <li>A vague, general point = 0 marks ❌</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"Suppliers.\"</em><br/>\n      Too vague — it doesn''t say WHAT about suppliers affects quality.</p>\n\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"The quality of raw materials / supplies used.\"</em><br/>\n      Specific and directly answers the question.</p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> Many candidates lost marks on this question by writing about the <em>cost</em> of raw materials rather than the <em>quality</em> of them. Always re-read the exact wording before writing your answer.</p>\n\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write a definition of quality (e.g. \"fit for purpose\") when asked for a <em>factor that affects</em> quality. These are different things — read the question carefully.</p>\n    ", "question": "What is the key lesson from the ''Bad Answer'' example, writing just ''Suppliers''?", "options": ["It doesn''t say WHAT about suppliers affects quality", "It is far too long for a 1-mark question answer", "It claims suppliers are never a valid factor", "It fails to mention Heinz Beanz by name"]}'::jsonb, '{"answer": 0, "explain": "The card explains that ''Suppliers'' alone is too vague — a 1-mark answer must be specific, such as ''the quality of raw materials/supplies used.''"}'::jsonb),
('business:4-2-quality-of-goods-services:tips:78be9f87', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Name It, Then Explain It", "reading": "\n      <p>A 2-mark <strong>''Explain''</strong> question needs two distinct steps: <strong>identify</strong> the point and then <strong>explain</strong> how or why it works. You will not get both marks for just naming something twice.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Identify (K):</strong> Name the concept clearly (e.g. \"quality control\")</li>\n        <li><strong>Step 2 — Explain (U):</strong> Explain what it involves or why it matters</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer (1 mark max):</strong><br/>\n      <em>\"Quality control is important because it makes goods better.\"</em><br/>\n      This only gets 1 mark — it names quality control but the explanation is too vague.</p>\n\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"Quality control (1) involves specialist inspectors checking finished goods to ensure they meet the required standard before reaching customers (1).\"</em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> Many candidates explained the right concept but named it incorrectly (e.g. describing quality control but calling it quality assurance). You must name AND correctly explain the same method. Less than half of candidates gained both marks on this type of question in recent papers.</p>\n    ", "question": "According to this card, what is the most common reason candidates lost marks on 2-mark explain questions?", "options": ["They explained the right concept but gave it the wrong name", "They included far too many examples instead of one clear explanation", "They explained the concept but never linked it to a case study", "They only wrote a single vague sentence with no real detail"]}'::jsonb, '{"answer": 0, "explain": "The examiner warning notes that many candidates explained the right concept but named it incorrectly, mixing up quality control and quality assurance."}'::jsonb),
('business:4-2-quality-of-goods-services:tips:fcc1c7cd', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "\n      <p>A 3-mark <strong>''Analyse''</strong> question is worth 3 marks split across Understanding, Application, and Analysis. You <strong>cannot score the analysis mark without first showing understanding</strong>. And you will score <strong>ZERO for analysis</strong> if you do not link to the specific business in the case study.</p>\n\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> Explain the concept or benefit clearly</li>\n        <li><strong>Step 2 — Application (APP):</strong> Link it directly to the specific business using evidence from the text (quote it, name the product, or reference a detail)</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> State the financial or operational impact on that business</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n      <em>\"Quality is important because it helps the business sell more.\"</em><br/>\n      This gets U only — no application to the business, no analysis of impact.</p>\n\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"Maintaining quality helps M&S protect its reputation (U). M&S is committed to high quality own-brand food, clothing and home products (APP). If quality slips, customers may switch to competitors, directly reducing M&S''s revenue and profits (AN).\"</em></p>\n\n      <p><strong>The ''So What?'' Rule for Analysis:</strong> Keep asking yourself ''So what?'' until you reach a bottom-line business impact.</p>\n      <ul>\n        <li>\"Quality builds reputation\" → So what?</li>\n        <li>\"Customers are more likely to return\" → So what?</li>\n        <li>\"This increases repeat sales and reduces the marketing cost of acquiring new customers\" ✅ NOW that''s analysis.</li>\n      </ul>\n    ", "question": "In the 3-mark ''Analyse'' formula, what happens if a candidate does not link their answer to the specific business in the case study?", "options": ["They score ZERO for analysis", "They still get full marks if the understanding is strong", "They lose only the application mark but keep the analysis mark", "They automatically get 2 out of 3 marks"]}'::jsonb, '{"answer": 0, "explain": "The card states you will score ZERO for analysis if you do not link to the specific business in the case study, since analysis must build on application."}'::jsonb),
('business:4-2-quality-of-goods-services:tips:18d97144', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tips', 'mcq', 1, '{"readingTitle": "Analyse Two Benefits/Impacts — 6 marks — Two 3-Mark Answers. No Conclusion Needed.", "reading": "\n      <p>A 6-mark question is simply <strong>a 3-mark question done twice</strong>. Write two separate, fully developed points, each following the U → APP → AN structure. Do <strong>not</strong> waste time writing a conclusion — there are zero marks available for evaluation here.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Point 1:</strong> U (1 mark) + APP (1 mark) + AN (1 mark) = 3 marks</li>\n        <li><strong>Point 2:</strong> U (1 mark) + APP (1 mark) + AN (1 mark) = 3 marks</li>\n      </ul>\n\n      <p><strong>Example Structure for Sainsbury''s quality question:</strong></p>\n      <ul>\n        <li><strong>Point 1 (U):</strong> Improving food quality can help Sainsbury''s improve its reputation...</li>\n        <li><strong>Point 1 (APP):</strong> ...as its Taste the Difference burgers and dishwasher tablets recently won a Which? Best Buy rating...</li>\n        <li><strong>Point 1 (AN):</strong> ...which may attract new customers and increase market share over competitors like Tesco and Morrisons.</li>\n        <li><strong>Point 2 (U):</strong> Improving quality can also reduce waste...</li>\n        <li><strong>Point 2 (APP):</strong> ...as Sainsbury''s is improving the quality of 3,000 own-brand products...</li>\n        <li><strong>Point 2 (AN):</strong> ...meaning less unsold food is thrown away each day, directly reducing costs and improving profit margins.</li>\n      </ul>\n\n      <p><strong>🚫 Do NOT write a conclusion.</strong> A 6-mark question does not reward evaluation — save the \"it depends on...\" language for 7–9 mark questions only.</p>\n    ", "question": "According to this card, should a 6-mark ''analyse two benefits'' answer include a conclusion?", "options": ["No — there are zero marks available for evaluation on this question type", "Yes — a conclusion is worth 2 of the 6 marks", "Yes, but only if both points are about the same benefit", "No — because conclusions are banned across every GCSE Business question"]}'::jsonb, '{"answer": 0, "explain": "The card explicitly says not to waste time writing a conclusion, as a 6-mark question does not reward evaluation — that language is saved for 7–9 mark questions."}'::jsonb),
('business:4-2-quality-of-goods-services:tips:83344998', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tips', 'mcq', 1, '{"readingTitle": "Explain Two Reasons — 4 marks — Two Points, Each with U + APP", "reading": "\n      <p>A 4-mark <strong>''Explain two reasons''</strong> question awards 1 mark for understanding each reason plus 1 mark for applying it to the specific business in the case study. Write two separate, clearly structured points.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Reason 1 (U):</strong> State the reason clearly → <strong>(APP):</strong> Link to the specific business</li>\n        <li><strong>Reason 2 (U):</strong> State a different reason → <strong>(APP):</strong> Link to the specific business</li>\n      </ul>\n\n      <p><strong>Example for JLR (Jaguar Land Rover):</strong></p>\n      <ul>\n        <li><em>\"Quality helps JLR maintain its reputation for luxury vehicles (U), which is especially important as it competes directly with premium German brands BMW and Mercedes (APP).\"</em></li>\n        <li><em>\"Quality helps JLR reduce the risk of costly product recalls (U), which would be extremely damaging for a company that sells expensive, complex cars where safety faults could be life-threatening (APP).\"</em></li>\n      </ul>\n\n      <p><strong>⚠️ Examiner Warning:</strong> Do not just list reasons without linking them to JLR. The application mark requires you to use a specific detail from the case study — mention the luxury segment, the competitors, the international markets, or the car manufacturing context.</p>\n    ", "question": "In the JLR example, what does the application mark require for each reason?", "options": ["A specific detail from the case study, such as the luxury car segment", "A general dictionary-style definition of what quality assurance actually means", "A comparison between JLR''s methods and Toyota''s kaizen system", "A statistic taken from a UK customer service satisfaction survey"]}'::jsonb, '{"answer": 0, "explain": "The examiner warning states the application mark requires a specific detail from the case study, such as the luxury segment, competitors, international markets, or manufacturing context."}'::jsonb),
('business:4-2-quality-of-goods-services:tips:322e2ec4', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'tips', 'mcq', 1, '{"readingTitle": "Quality Control vs Quality Assurance — Distinguish — The Most Common Mix-Up in This Topic", "reading": "\n      <p>Examiners repeatedly report that students confuse quality control and quality assurance. This mix-up alone costs thousands of marks across every exam series. Learn this distinction perfectly.</p>\n\n      <p><strong>The Key Difference in One Sentence:</strong><br/>\n      Quality control = <em>CHECKING</em> by specialists (after or during production). Quality assurance = <em>PREVENTING</em> by all workers (throughout production).</p>\n\n      <p><strong>Quick Reference Table:</strong></p>\n      <ul>\n        <li><strong>Who checks quality?</strong> QC = specialist inspectors only | QA = every single worker</li>\n        <li><strong>When is quality checked?</strong> QC = end of production or sampling | QA = at every stage continuously</li>\n        <li><strong>Does it disrupt production?</strong> QC = No | QA = Yes (workers stop to check)</li>\n        <li><strong>Does it prevent waste?</strong> QC = No (faults already made) | QA = Yes (caught early)</li>\n        <li><strong>Does it motivate workers?</strong> QC = No (workers have no responsibility) | QA = Yes (workers feel valued)</li>\n      </ul>\n\n      <p><strong>Real-World Memory Aid:</strong></p>\n      <ul>\n        <li><strong>Quality Control:</strong> Heinz Beanz machine ejecting wrong-weight cans ✅</li>\n        <li><strong>Quality Assurance:</strong> Toyota workers suggesting improvements in team meetings ✅</li>\n      </ul>\n\n      <p><strong>⚠️ AfL Note from Examiners:</strong> Creating key term lists, flashcards and mini tests is the most effective way to prevent this mix-up before an exam.</p>\n    ", "question": "According to the ''Real-World Memory Aid'', which example represents quality assurance?", "options": ["Toyota workers suggesting quality improvements in meetings", "Heinz Beanz machines automatically ejecting faulty cans", "ABC Bicycles employees wearing white inspection gloves", "Whirlpool recalling faulty washing machines from customers"]}'::jsonb, '{"answer": 0, "explain": "The card''s memory aid pairs quality control with the Heinz Beanz machine ejecting faulty cans, and quality assurance with Toyota workers suggesting improvements in team meetings."}'::jsonb),
