('business:4-2-quality-of-goods-services:match:4c05a4bd', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quality”?", "options": ["A system for inspecting the quality of goods or services produced by specialist inspectors to ensure they meet a good standard.", "An approach that involves the whole business focusing on quality, aiming to prevent quality problems from arising at every stage of production.", "A product or service that is fit for purpose, meets legislative rules, and meets customer expectations.", "Goods which customers take back to the shop because there are problems with the quality of them."]}'::jsonb, '{"answer": 2, "explain": "“Quality” means: A product or service that is fit for purpose, meets legislative rules, and meets customer expectations."}'::jsonb),
('business:4-2-quality-of-goods-services:match:f7116f73', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quality Control”?", "options": ["An approach that involves the whole business focusing on quality, aiming to prevent quality problems from arising at every stage of production.", "Goods which customers take back to the shop because there are problems with the quality of them.", "When a fault occurs with a product and the business asks for the product to be brought back so it can be repaired or replaced.", "A system for inspecting the quality of goods or services produced by specialist inspectors to ensure they meet a good standard."]}'::jsonb, '{"answer": 3, "explain": "“Quality Control” means: A system for inspecting the quality of goods or services produced by specialist inspectors to ensure they meet a good standard."}'::jsonb),
('business:4-2-quality-of-goods-services:match:f963774f', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quality Assurance”?", "options": ["Goods which customers take back to the shop because there are problems with the quality of them.", "When a fault occurs with a product and the business asks for the product to be brought back so it can be repaired or replaced.", "A person who pretends to be a normal customer but secretly evaluates whether the service provided meets the required standard.", "An approach that involves the whole business focusing on quality, aiming to prevent quality problems from arising at every stage of production."]}'::jsonb, '{"answer": 3, "explain": "“Quality Assurance” means: An approach that involves the whole business focusing on quality, aiming to prevent quality problems from arising at every stage of production."}'::jsonb),
('business:4-2-quality-of-goods-services:match:0239dd17', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Returns”?", "options": ["Goods which customers take back to the shop because there are problems with the quality of them.", "When a fault occurs with a product and the business asks for the product to be brought back so it can be repaired or replaced.", "A person who pretends to be a normal customer but secretly evaluates whether the service provided meets the required standard.", "A product that fulfils its intended function and meets the reasonable expectations of the customer for the price paid."]}'::jsonb, '{"answer": 0, "explain": "“Returns” means: Goods which customers take back to the shop because there are problems with the quality of them."}'::jsonb),
('business:4-2-quality-of-goods-services:match:89cc40df', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Recalls”?", "options": ["A person who pretends to be a normal customer but secretly evaluates whether the service provided meets the required standard.", "A product that fulfils its intended function and meets the reasonable expectations of the customer for the price paid.", "Resources (materials, labour, time) used to produce goods that turn out to be faulty and cannot be sold at full price.", "When a fault occurs with a product and the business asks for the product to be brought back so it can be repaired or replaced."]}'::jsonb, '{"answer": 3, "explain": "“Recalls” means: When a fault occurs with a product and the business asks for the product to be brought back so it can be repaired or replaced."}'::jsonb),
('business:4-2-quality-of-goods-services:match:7ce5518d', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Mystery Shopper”?", "options": ["A product that fulfils its intended function and meets the reasonable expectations of the customer for the price paid.", "Resources (materials, labour, time) used to produce goods that turn out to be faulty and cannot be sold at full price.", "A method of quality control where customers are asked to rate their experience so a business can identify problems and improvements.", "A person who pretends to be a normal customer but secretly evaluates whether the service provided meets the required standard."]}'::jsonb, '{"answer": 3, "explain": "“Mystery Shopper” means: A person who pretends to be a normal customer but secretly evaluates whether the service provided meets the required standard."}'::jsonb),
('business:4-2-quality-of-goods-services:match:d12a8aae', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fit for Purpose”?", "options": ["Resources (materials, labour, time) used to produce goods that turn out to be faulty and cannot be sold at full price.", "A product that fulfils its intended function and meets the reasonable expectations of the customer for the price paid.", "A method of quality control where customers are asked to rate their experience so a business can identify problems and improvements.", "A key principle of quality assurance (associated with Toyota) where all employees constantly look for ways to improve quality and reduce waste."]}'::jsonb, '{"answer": 1, "explain": "“Fit for Purpose” means: A product that fulfils its intended function and meets the reasonable expectations of the customer for the price paid."}'::jsonb),
('business:4-2-quality-of-goods-services:match:cf26da78', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Waste (in quality context)”?", "options": ["A method of quality control where customers are asked to rate their experience so a business can identify problems and improvements.", "A key principle of quality assurance (associated with Toyota) where all employees constantly look for ways to improve quality and reduce waste.", "An environment in a business where every employee at every level takes personal responsibility for maintaining quality standards.", "Resources (materials, labour, time) used to produce goods that turn out to be faulty and cannot be sold at full price."]}'::jsonb, '{"answer": 3, "explain": "“Waste (in quality context)” means: Resources (materials, labour, time) used to produce goods that turn out to be faulty and cannot be sold at full price."}'::jsonb),
('business:4-2-quality-of-goods-services:match:ad390920', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Customer Satisfaction Survey”?", "options": ["A key principle of quality assurance (associated with Toyota) where all employees constantly look for ways to improve quality and reduce waste.", "A method of quality control where customers are asked to rate their experience so a business can identify problems and improvements.", "An environment in a business where every employee at every level takes personal responsibility for maintaining quality standards.", "Goods that fail quality inspection but can still be sold to customers at a reduced price, resulting in lower revenue for the business."]}'::jsonb, '{"answer": 1, "explain": "“Customer Satisfaction Survey” means: A method of quality control where customers are asked to rate their experience so a business can identify problems and improvements."}'::jsonb),
('business:4-2-quality-of-goods-services:match:9d512ee7', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Continuous Improvement”?", "options": ["An environment in a business where every employee at every level takes personal responsibility for maintaining quality standards.", "Goods that fail quality inspection but can still be sold to customers at a reduced price, resulting in lower revenue for the business.", "A key principle of quality assurance (associated with Toyota) where all employees constantly look for ways to improve quality and reduce waste.", "A product or service that is fit for purpose, meets legislative rules, and meets customer expectations."]}'::jsonb, '{"answer": 2, "explain": "“Continuous Improvement” means: A key principle of quality assurance (associated with Toyota) where all employees constantly look for ways to improve quality and reduce waste."}'::jsonb)
